        return computeThreeSumSmaller(nums, 0, target);
    }

    private int computeThreeSumSmaller(int[] nums, int start, int target) {
        int count = 0;
        for (int i = start; i < nums.length - 2; ++i) {
            int j = i + 1, k = nums.length - 1;
            while (j < k) {
                if (nums[i] + nums[j] + nums[k] < target) {
                    count += k - j;
                    ++j;
                } else {
                    --k;
                }
            }
        }
        return count;
    }
}

