import java.util.ArrayList;
import java.util.List;

public class Solution {
    public List<String> addOperators(String num, int target) {
        List<String> res = new ArrayList<>();

        if (num.length() == 0) return res;

        long currVal = Long.parseLong(num.substring(0, 1));
        helper(num, target, 1, currVal, currVal, "" + num.charAt(0), res);

        for (int i = 2; i <= num.length(); ++i) {
            if (num.charAt(i - 2) == '0') break;
            long val = Long.parseLong(num.substring(i - 2, i));

            helper(num, target, i, currVal + val, val, "" + num.charAt(i - 1), res);
            helper(num, target, i, currVal - val, -val, "-" + num.charAt(i - 1), res);
            helper(num, target, i, currVal - prevVal + prevVal * val, prevVal * val, "*" + num.charAt(i - 1), res);
        }

        return res;
    }
}

