public class Solution {
    public List<Integer> findMinHeightTrees(int n, int[][] edges) {
        if (n == 1) {
            List<Integer> result = new ArrayList<>();
            result.add(0);
            return result;
        }

        int[] degrees = new int[n];
        List<List<Integer>> adjList = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            adjList.add(new ArrayList<>());
        }

        // Build adjacency list and calculate degrees
        for (int[] edge : edges) {
            adjList.get(edge[0]).add(edge[1]);
            adjList.get(edge[1]).add(edge[0]);
            degrees[edge[0]]++;
            degrees[edge[1]]++;
        }

        Queue<Integer> queue = new LinkedList<>();
        // Add leaves to the queue
        for (int i = 0; i < n; i++) {
            if (degrees[i] == 1) queue.add(i);
        }

        while (n > 2) {
            int leavesSize = queue.size();
            n -= leavesSize;
            // Remove leaves and update degrees of neighbors
            for (int i = 0; i < leavesSize; i++) {
                int leaf = queue.poll();
                for (int neighbor : adjList.get(leaf)) {
                    if (--degrees[neighbor] == 1) queue.add(neighbor);
                }
            }
        }

        return new ArrayList<>(queue);
    }
}

