import java.util.LinkedList;
import java.util.Queue;

public class Solution {
    public int shortestDistance(int[][] grid) {
        int m = grid.length;
        int n = grid[0].length;

        int[][] total_count = new int[m][n];
        int[][] dist_sum = new int[m][n];
        int house_count = 0;

        int[][] dirs = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 1) {
                    house_count++;
                    Queue<int[]> q = new LinkedList<>();
                    q.offer(new int[]{i, j});
                    boolean[][] visited = new boolean[m][n];
                    bfs(q, visited, dist_sum, total_count);
                }
            }
        }

        return findMinDistance(total_count, dist_sum, house_count);
    }

    private void bfs(Queue<int[]> q, boolean[][] visited, int[][] dist_sum, int[][] total_count) {
        int level = 1;
        while (!q.isEmpty()) {
            int sz = q.size();
            for (int q_i = 0; q_i < sz; q_i++) {
                int[] cur = q.poll();
                int x = cur[0];
                int y = cur[1];
                updateNeighbors(x, y, level, visited, dist_sum, total_count);
            }
            level++;
        }
    }

    private void updateNeighbors(int x, int y, int level, boolean[][] visited, int[][] dist_sum, int[][] total_count) {
        for (int[] dir : dirs) {
            int x_new = x + dir[0];
            int y_new = y + dir[1];
            if (x_new >= 0 && x_new < m && y_new >= 0 && y_new < n && !visited[x_new][y_new] && grid[x_new][y_new] == 0) {
                visited[x_new][y_new] = true;
                q.offer(new int[]{x_new, y_new});
                dist_sum[x_new][y_new] += level;
                total_count[x_new][y_new]++;
            }
        }
    }

    private int findMinDistance(int[][] total_count, int[][] dist_sum, int house_count) {
        int min_dist = Integer.MAX_VALUE;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (total_count[i][j] == house_count) {
                    min_dist = Math.min(min_dist, dist_sum[i][j]);
                }
            }
        }

        return min_dist == Integer.MAX_VALUE ? -1 : min_dist;
    }
}

