public class Solution {
    public String convertToBase7(int num) {
        if (num == 0) return "0";
        StringBuilder result = new StringBuilder();
        boolean negative = num < 0;
        if (negative) num *= -1;
        while (num > 0) {
            result.insert(0, num % 7);
            num /= 7;
        }
        return negative ? "-" + result.toString() : result.toString();
    }
}

