    public int change(int amount, int[] coins) {
        int[] dp = new int[amount + 1];
        dp[0] = 1;

        // Initialize the DP array with base case
        for (int i = 1; i <= amount; i++) {
            dp[i] = 0;
        }

        // Iterate over each coin type
        for (int coin : coins) {
            // Update the DP array based on current coin value
            for (int i = coin; i <= amount; i++) {
                dp[i] += dp[i - coin];
            }
        }

        return dp[amount];
    }
}

